define i8 @scmp_lt_with_branch_weights(i32 %a, i32 %b) {
entry:
  %cmp = icmp slt i32 %a, %b
  br i1 %cmp, label %lt, label %not_lt, !prof !0

lt:
  ret i8 1

not_lt:
  ret i8 2
}

!0 = !{!"branch_weights", i32 64, i32 12}

define i8 @ucmp_eq_with_unpredictable(i32 %a, i32 %b) {
entry:
  %cmp = icmp eq i32 %a, %b
  br i1 %cmp, label %eq, label %ne, !unpredictable !0

eq:
  ret i8 9

ne:
  ret i8 10
}

!0 = !{}

